package com.food_application.utility;
import com.food_application.DAOApplication.NotificationDAOImpl; import com.food_application.model.Notification; import com.food_application.model.NotificationType; import com.food_application.model.OrderStatus;
public final class NotificationService { private NotificationService(){} public static void send(int customerId,Integer orderId,String title,String message,NotificationType type){try{new NotificationDAOImpl().addNotification(new Notification(customerId,orderId,title,message,type.name()));}catch(Exception e){e.printStackTrace();}}
 public static void forStatus(int customerId,int orderId,OrderStatus s){String t=null,m=null;NotificationType type=NotificationType.ORDER;switch(s){case ACCEPTED:t="Restaurant Accepted";m="The restaurant has accepted your order.";break;case PREPARING:t="Preparing Food";m="Your food is being freshly prepared.";break;case READY:t="Order Ready";m="Your food has been packed.";break;case ASSIGNED:t="Delivery Assigned";m="A delivery partner has been assigned to your order.";type=NotificationType.DELIVERY;break;case PICKED_UP:t="Picked Up";m="Your order has been picked up.";type=NotificationType.DELIVERY;break;case OUT_FOR_DELIVERY:t="Out For Delivery";m="Your order is on the way.";type=NotificationType.DELIVERY;break;case DELIVERED:t="Delivered";m="Enjoy your meal!";type=NotificationType.DELIVERY;break;case CANCELLED:t="Order Cancelled";m="Your order has been cancelled.";break;default:break;}if(t!=null)send(customerId,orderId,t,m,type);}}
